module div_8bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output res_valid,
    output [15:0] result
);

    reg [15:0] sr;
    reg [7:0] divisor_reg;
    reg [3:0] cnt;
    reg start_cnt;
    reg neg_divisor;
    reg res_valid_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            sr <= 0;
            divisor_reg <= 0;
            cnt <= 0;
            start_cnt <= 0;
            neg_divisor <= 0;
            res_valid_reg <= 0;
        end else if (opn_valid) begin
            if (sign) begin
                divisor_reg <= divisor;
                neg_divisor <= divisor[7];
            end else begin
                divisor_reg <= divisor;
                neg_divisor <= 0;
            end
            sr <= {16{dividend[7]}} | dividend;
            start_cnt <= 1;
        end else if (start_cnt) begin
            if (cnt < 8) begin
                if (sr[15:8] >= divisor_reg) begin
                    sr <= {sr[14:0], 1'b1};
                    sr[15:8] <= sr[15:8] - divisor_reg;
                end else begin
                    sr <= {sr[14:0], 1'b0};
                end
                cnt <= cnt + 1;
            end else begin
                if (neg_divisor) begin
                    sr[15:8] <= ~sr[15:8] + 1;
                end
                res_valid_reg <= 1;
                start_cnt <= 0;
            end
        end
    end

    assign res_valid = res_valid_reg;
    assign result = sr;

endmodule

